class NewsletterController extends Controller { use ApiResponses; public function subscribe(Request $r): JsonResponse { $d=$r->validate(['email'=>'required|email|max:190','name'=>'nullable|string|max:190','phone'=>'nullable|string|max:60','whatsapp_number'=>'nullable|string|max:60','interests'=>'array','subscribed_categories'=>'array','source'=>'nullable|string|max:80']); DB::table('newsletter_subscribers')->updateOrInsert(['email'=>$d['email']], ['name'=>$d['name']??null,'phone'=>$d['phone']??null,'whatsapp_number'=>$d['whatsapp_number']??null,'interests'=>json_encode($d['interests']??[]),'subscribed_categories'=>json_encode($d['subscribed_categories']??[]),'source'=>$d['source']??'api','status'=>'subscribed','double_opt_in_token'=>Str::random(48),'updated_at'=>now(),'created_at'=>now()]); return $this->success(['message'=>'Subscribed.'],201); } public function confirm(Request $r): JsonResponse { $d=$r->validate(['token'=>'required|string']); DB::table('newsletter_subscribers')->where('double_opt_in_token',$d['token'])->update(['confirmed_at'=>now(),'updated_at'=>now()]); return $this->success(['message'=>'Confirmed.']); } public function unsubscribe(Request $r): JsonResponse { $d=$r->validate(['email'=>'required|email']); DB::table('newsletter_subscribers')->where('email',$d['email'])->update(['status'=>'unsubscribed','unsubscribed_at'=>now(),'updated_at'=>now()]); DB::table('suppression_lists')->insert(['channel'=>'email','email'=>$d['email'],'reason'=>'newsletter_unsubscribe','suppressed_at'=>now(),'created_at'=>now(),'updated_at'=>now()]); return $this->success(['message'=>'Unsubscribed.']); } public function preferences(Request $r): JsonResponse { $d=$r->validate(['email'=>'required|email']); return $this->success(DB::table('newsletter_subscribers')->where('email',$d['email'])->first()); } public function updatePreferences(Request $r): JsonResponse { $d=$r->validate(['email'=>'required|email','interests'=>'array','subscribed_categories'=>'array']); DB::table('newsletter_subscribers')->where('email',$d['email'])->update(['interests'=>json_encode($d['interests']??[]),'subscribed_categories'=>json_encode($d['subscribed_categories']??[]),'updated_at'=>now()]); return $this->success(['message'=>'Preferences updated.']); } }
